option.raw:
const data = ctx.data?.objects || [];
return {
  title: { text: '物料库存价值分布', left: 'center', textStyle: { fontSize: 14 } },
  tooltip: { trigger: 'item', formatter: p => `${p.name}<br/>库存价值: ¥${(p.value/10000).toFixed(1)}万<br/>占比: ${p.percent}%` },
  legend: { bottom: 0, type: 'scroll' },
  series: [{
    type: 'pie', radius: ['40%', '70%'], center: ['50%', '45%'],
    label: { formatter: '{b}\n{d}%', fontSize: 11 },
    data: data.map(d => ({ name: d.category_name, value: parseFloat(d.stock_value || 0) })),
    emphasis: { itemStyle: { shadowBlur: 10, shadowColor: 'rgba(0,0,0,0.3)' } },
    color: ['#1677ff', '#52c41a', '#fa8c16', '#722ed1', '#13c2c2', '#eb2f96']
  }]
};
